import { useState } from 'react'
import { motion } from 'framer-motion'
import { FiGithub, FiLinkedin, FiMail, FiSend, FiMapPin, FiDownload } from 'react-icons/fi'
import SectionHeading from './SectionHeading'
import emailjs from '@emailjs/browser'

// ─────────────────────────────────────────────
// 1. Go to https://www.emailjs.com and sign up (free)
// 2. Create a Service (Gmail recommended) → copy Service ID
// 3. Create an Email Template → copy Template ID
//    In the template use these variables:
//      {{from_name}}  {{from_email}}  {{message}}
// 4. Go to Account → API Keys → copy Public Key
// 5. Replace the three values below
// ─────────────────────────────────────────────
const EMAILJS_SERVICE_ID  = 'service_wt2cx26'   // e.g. 'service_abc123'
const EMAILJS_TEMPLATE_ID = 'template_72s2q6c'  // e.g. 'template_xyz789'
const EMAILJS_PUBLIC_KEY  = 'IdOuCckt2buMBc58r'   // e.g. 'AbCdEfGhIjKlMnOp'

// ─────────────────────────────────────────────
// Paste your resume base64 string here.
// Copy the RESUME_BASE64 value from your Navbar.jsx
// ─────────────────────────────────────────────
const RESUME_BASE64 = ''

const contactLinks = [
  {
    icon: <FiMail size={20} />,
    label: 'Email',
    value: 'manthansingh104@gmail.com',
    href: 'mailto:manthansingh104@gmail.com',
    color: 'hover:border-blue-500/50 hover:text-blue-400',
  },
  {
    icon: <FiGithub size={20} />,
    label: 'GitHub',
    value: 'github.com/manthansingh104-cmd',
    href: 'https://github.com/manthansingh104-cmd',
    color: 'hover:border-slate-400/50 hover:text-slate-300',
  },
  {
    icon: <FiLinkedin size={20} />,
    label: 'LinkedIn',
    value: 'manthan-singh-3a7013373',
    href: 'https://www.linkedin.com/in/manthan-singh-3a7013373',
    color: 'hover:border-blue-500/50 hover:text-blue-400',
  },
  {
    icon: <FiMapPin size={20} />,
    label: 'Location',
    value: 'Ludhiana, Punjab, India',
    href: null,
    color: '',
  },
]

function downloadResume() {
  const byteChars = atob(RESUME_BASE64)
  const byteNums = new Uint8Array(byteChars.length)
  for (let i = 0; i < byteChars.length; i++) {
    byteNums[i] = byteChars.charCodeAt(i)
  }
  const blob = new Blob([byteNums], { type: 'application/pdf' })
  const url = URL.createObjectURL(blob)
  const a = document.createElement('a')
  a.href = url
  a.download = 'Manthan_Singh_Resume.pdf'
  a.click()
  URL.revokeObjectURL(url)
}

export default function Contact() {
  const [form, setForm]     = useState({ name: '', email: '', message: '' })
  const [status, setStatus] = useState(null) // 'sending' | 'sent' | 'error'

  const handleChange = e =>
    setForm(f => ({ ...f, [e.target.name]: e.target.value }))

  const handleSubmit = async e => {
    e.preventDefault()
    setStatus('sending')

    try {
      await emailjs.send(
        EMAILJS_SERVICE_ID,
        EMAILJS_TEMPLATE_ID,
        {
          from_name:  form.name,
          from_email: form.email,
          message:    form.message,
        },
        EMAILJS_PUBLIC_KEY
      )
      setStatus('sent')
      setForm({ name: '', email: '', message: '' })
      setTimeout(() => setStatus(null), 4000)
    } catch (err) {
      console.error('EmailJS error:', err)
      setStatus('error')
      setTimeout(() => setStatus(null), 4000)
    }
  }

  return (
    <section id="contact" className="section-padding bg-surface/30">
      <div className="max-w-6xl mx-auto px-6">
        <SectionHeading
          eyebrow="// let's connect"
          title="Get In Touch"
          subtitle="Have an internship opportunity or just want to say hello? My inbox is always open."
        />

        <div className="grid lg:grid-cols-2 gap-12">

          {/* Left — Info */}
          <motion.div
            initial={{ opacity: 0, x: -24 }}
            whileInView={{ opacity: 1, x: 0 }}
            viewport={{ once: true }}
            transition={{ duration: 0.5 }}
            className="space-y-6"
          >
            <p className="text-slate-400 leading-relaxed">
              I'm currently looking for <span className="text-white font-medium">frontend developer internship</span>{' '}
              opportunities. Whether you have a role in mind, a project to collaborate on, or just
              want to connect — feel free to reach out!
            </p>

            <div className="space-y-3">
              {contactLinks.map(link => (
                <div
                  key={link.label}
                  className={`glass rounded-xl p-4 flex items-center gap-4 border border-border transition-all duration-200 ${link.color}`}
                >
                  <div className="text-muted">{link.icon}</div>
                  <div>
                    <p className="text-xs text-muted font-mono">{link.label}</p>
                    {link.href ? (
                      <a
                        href={link.href}
                        target={link.href.startsWith('http') ? '_blank' : undefined}
                        rel="noreferrer"
                        className="text-sm text-slate-300 hover:text-white transition-colors"
                      >
                        {link.value}
                      </a>
                    ) : (
                      <p className="text-sm text-slate-300">{link.value}</p>
                    )}
                  </div>
                </div>
              ))}
            </div>

            {/* Download Resume button */}
            <div className="pt-4">
              <button
                onClick={downloadResume}
                className="inline-flex items-center gap-2 px-6 py-3 rounded-xl bg-gradient-accent text-white font-semibold text-sm hover:opacity-90 transition-all shadow-lg shadow-accent/20"
              >
                <FiDownload size={16} /> Download Resume
              </button>
            </div>
          </motion.div>

          {/* Right — Form */}
          <motion.div
            initial={{ opacity: 0, x: 24 }}
            whileInView={{ opacity: 1, x: 0 }}
            viewport={{ once: true }}
            transition={{ duration: 0.5, delay: 0.15 }}
          >
            <form onSubmit={handleSubmit} className="glass rounded-2xl p-8 space-y-5">
              <div>
                <label className="block text-sm text-muted mb-2 font-mono">Name</label>
                <input
                  type="text"
                  name="name"
                  required
                  value={form.name}
                  onChange={handleChange}
                  placeholder="Your name"
                  className="w-full bg-surface border border-border rounded-xl px-4 py-3 text-sm text-white placeholder-muted focus:outline-none focus:border-accent transition-colors"
                />
              </div>
              <div>
                <label className="block text-sm text-muted mb-2 font-mono">Email</label>
                <input
                  type="email"
                  name="email"
                  required
                  value={form.email}
                  onChange={handleChange}
                  placeholder="your@email.com"
                  className="w-full bg-surface border border-border rounded-xl px-4 py-3 text-sm text-white placeholder-muted focus:outline-none focus:border-accent transition-colors"
                />
              </div>
              <div>
                <label className="block text-sm text-muted mb-2 font-mono">Message</label>
                <textarea
                  name="message"
                  required
                  rows={5}
                  value={form.message}
                  onChange={handleChange}
                  placeholder="Tell me about your opportunity or project..."
                  className="w-full bg-surface border border-border rounded-xl px-4 py-3 text-sm text-white placeholder-muted focus:outline-none focus:border-accent transition-colors resize-none"
                />
              </div>

              <button
                type="submit"
                disabled={status === 'sending'}
                className="w-full flex items-center justify-center gap-2 py-3 rounded-xl bg-gradient-accent text-white font-semibold text-sm hover:opacity-90 active:scale-[0.98] transition-all shadow-lg shadow-accent/20 disabled:opacity-60 disabled:cursor-not-allowed"
              >
                {status === 'sending' && (
                  <svg className="animate-spin h-4 w-4" viewBox="0 0 24 24" fill="none">
                    <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"/>
                    <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8v8H4z"/>
                  </svg>
                )}
                {status === 'sending' && 'Sending…'}
                {status === 'sent'    && '✓ Message sent!'}
                {status === 'error'   && '✗ Failed — try again'}
                {!status              && <><FiSend size={15} /> Send Message</>}
              </button>

              <p className="text-center text-xs text-muted">
                Or email me directly at{' '}
                <a href="mailto:manthansingh104@gmail.com" className="text-accent hover:underline">
                  manthansingh104@gmail.com
                </a>
              </p>
            </form>
          </motion.div>
        </div>
      </div>
    </section>
  )
}